"use client";
import { useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
const stops: [string, number][]=[['Explore',25],['Target',55],['Stretch',85]];
export default function RangeIntentComposer(){const [value,setValue]=useState(55);const reduced=useReducedMotion();const active=stops.findIndex((stop)=>stop[1]===value);return <form className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-[0_10px_28px_rgba(17,17,17,.06)]"><label htmlFor="intent-range" className="text-xs font-bold uppercase tracking-[.14em] text-[#4a4a4f]">monthly budget</label><output aria-live="polite" className="mt-1 block text-2xl font-black text-[#111]">${value}k</output><div className="mt-3 flex flex-wrap gap-2">{stops.map((stop)=><motion.button key={stop[0]} type="button" aria-pressed={value===stop[1]} onClick={()=>setValue(stop[1])} whileHover={reduced?undefined:{y:-2}} whileTap={reduced?undefined:{y:1}} className="min-h-11 rounded-xl border border-[#ececee] px-3 text-sm font-bold outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]">{stop[0]}</motion.button>)}</div><input id="intent-range" type="range" min="0" max="100" value={value} onChange={event=>setValue(Number(event.target.value))} className="mt-5 w-full accent-[#0891b2]"/><div className="mt-2 h-1 rounded-full bg-[#f4f5f6]"><motion.i animate={{x:`calc(${value}% - 8px)`}} transition={reduced?{duration:.12}:{type:'spring',stiffness:340,damping:28}} className="block h-4 w-4 -translate-y-1.5 rounded-full bg-[#0891b2]"/></div><p className="mt-3 text-xs text-[#4a4a4f]">{active>=0?`${stops[active][0]} intent selected.`:'Custom budget selected.'}</p></form>}
